369	// ValidateForExecuteLoopViaService is the production replacement for
370	// Runner.ValidateForExecuteLoop. When harness is empty it is a no-op (routing
371	// will pick at claim time). When harness is specified it confirms the harness
372	// exists in the service registry and (when model is set) attempts a
373	// ResolveRoute pre-flight.
374	func ValidateForExecuteLoopViaService(ctx context.Context, workDir, harnessName, model, provider, modelRef string) error {
375		if harnessName == "" {
376			return nil
377		}
378		if ctx == nil {
379			ctx = context.Background()
380		}
381		svc, err := NewServiceFromWorkDir(workDir)
382		if err != nil {
383			return fmt.Errorf("agent: build service: %w", err)
384		}
385		infos, err := svc.ListHarnesses(ctx)
386		if err != nil {
387			return fmt.Errorf("agent: list harnesses: %w", err)
388		}
389		found := false
390		for _, info := range infos {
391			if info.Name == harnessName {
392				found = true
393				if !info.Available {
394					return fmt.Errorf("agent: harness %s not available", harnessName)
395				}
396				break
397			}
398		}
399		if !found {
400			return fmt.Errorf("agent: unknown harness: %s", harnessName)
401		}
402	
403		// Pre-flight orphan-model check via ResolveRoute. Only meaningful when a
404		// model is provided and provider/model-ref are not set.
405		if model != "" && provider == "" && modelRef == "" && harnessName == "agent" {
406			if _, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{
407				Model:    model,
408				Harness:  harnessName,
409				ModelRef: modelRef,
410				Provider: provider,
411			}); err != nil {
412				return fmt.Errorf("agent: model %q is not routable: %w", model, err)
413			}
414		}
415		return nil
416	}
